import{_ as a,o as t,c as r,ag as i}from"./chunks/framework.DXGyWiRo.js";const p=JSON.parse('{"title":"Contribute","description":"","frontmatter":{},"headers":[],"relativePath":"contribution.md","filePath":"contribution.md"}'),n={name:"contribution.md"};function o(l,e,s,c,u,d){return t(),r("div",null,[...e[0]||(e[0]=[i('<h1 id="contribute" tabindex="-1">Contribute <a class="header-anchor" href="#contribute" aria-label="Permalink to &quot;Contribute&quot;">​</a></h1><p>MathClaw is organized as a working product system rather than a single demo page. Contributions are most useful when they improve one of the following layers clearly:</p><ul><li><strong>Learning experience</strong>: solver workspace, study planning, graph readability, attachment output styles.</li><li><strong>System operability</strong>: runtime status, heartbeat visibility, channel stability, configuration portability.</li><li><strong>Memory quality</strong>: better graph extraction, more stable daily / weekly summaries, cleaner workspace data flow.</li></ul><h2 id="recommended-contribution-areas" tabindex="-1">Recommended contribution areas <a class="header-anchor" href="#recommended-contribution-areas" aria-label="Permalink to &quot;Recommended contribution areas&quot;">​</a></h2><h3 id="_1-product-surfaces" tabindex="-1">1. Product surfaces <a class="header-anchor" href="#_1-product-surfaces" aria-label="Permalink to &quot;1. Product surfaces&quot;">​</a></h3><ul><li>Improve solver rendering for long mathematical answers.</li><li>Refine study planning information density.</li><li>Improve graph readability and node relationship presentation.</li><li>Make Skills, heartbeat, and runtime pages easier to operate.</li></ul><h3 id="_2-deployment-and-portability" tabindex="-1">2. Deployment and portability <a class="header-anchor" href="#_2-deployment-and-portability" aria-label="Permalink to &quot;2. Deployment and portability&quot;">​</a></h3><ul><li>Remove machine-specific assumptions from configs and startup scripts.</li><li>Improve startup paths, channel onboarding, and environment-variable handling.</li><li>Keep GitHub Pages and console-facing docs aligned with the actual repository structure.</li></ul><h3 id="_3-documentation" tabindex="-1">3. Documentation <a class="header-anchor" href="#_3-documentation" aria-label="Permalink to &quot;3. Documentation&quot;">​</a></h3><ul><li>Keep README and docs aligned with the running product.</li><li>Prefer product-facing explanations over migration notes.</li><li>When updating screenshots, use the current MathClaw console rather than placeholder media.</li></ul><h2 id="before-opening-a-pr" tabindex="-1">Before opening a PR <a class="header-anchor" href="#before-opening-a-pr" aria-label="Permalink to &quot;Before opening a PR&quot;">​</a></h2><ol><li>Verify the related page still renders correctly.</li><li>Avoid including runtime history or transient workspace artifacts unless they are intentionally tracked.</li><li>Keep brand naming consistent as <strong>MathClaw</strong> in user-facing surfaces.</li></ol><h2 id="related-repositories" tabindex="-1">Related repositories <a class="header-anchor" href="#related-repositories" aria-label="Permalink to &quot;Related repositories&quot;">​</a></h2><ul><li><a href="https://github.com/MathClaw-ruc/MathClaw" target="_blank" rel="noreferrer">MathClaw</a></li><li><a href="https://github.com/MathClaw-ruc/MathClaw.github.io" target="_blank" rel="noreferrer">MathClaw.github.io</a></li></ul>',14)])])}const m=a(n,[["render",o]]);export{p as __pageData,m as default};
